import React, { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import axios from 'axios';
import ArtisanCard from '../components/ArtisanCard';

const SearchResults = () => {
    const [artisans, setArtisans] = useState([]);
    const [loading, setLoading] = useState(true);
    const { search } = useLocation();
    const query = new URLSearchParams(search).get('q');

    useEffect(() => {
        setLoading(true);
        axios.get(`http://localhost:5000/api/artisans?q=${query}`)
            .then(res => {
                setArtisans(res.data);
                setLoading(false);
            })
            .catch(err => {
                console.error(err);
                setLoading(false);
            });
    }, [query]);

    if (loading) return <div className="container py-5">Recherche en cours...</div>;

    return (
        <div className="container py-4">
            <h2 className="mb-4">Résultats pour : "{query}"</h2>
            <div className="row">
                {artisans.length > 0 ? (
                    artisans.map(artisan => <ArtisanCard key={artisan.id} artisan={artisan} />)
                ) : (
                    <div className="alert alert-warning">Aucun artisan ne correspond à votre recherche.</div>
                )}
            </div>
        </div>
    );
};

export default SearchResults;
